### 5. **Provider Factory Function Pattern**

**Key Example**: `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775398555984-v7j1q3/packages/replicate/src/replicate-provider.ts`

For a **minimal image-only provider**, follow this structure:

```typescript
import {
  ImageModelV3,
  NoSuchModelError,
  ProviderV3,
} from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import { loadApiKey, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /**
   * API key for authentication.
   * It defaults to the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Use a different URL prefix for API calls.
   * The default prefix is `https://api.pixelart.com/v1`.
   */
  baseURL?: string;

  /**
   * Custom headers to include in the requests.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation.
   */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image generation model.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a PixelArt image generation model.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart',
      baseURL: options.baseURL ?? 'https://api.pixelart.com/v1',
      headers: getHeaders(),
      fetch: options.fetch,
    });

  const languageModel = (modelId: string) => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'languageModel',
    });
  };

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'embeddingModel',
    });
  };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel,
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const pixelart = createPixelArt();
```

**Critical Pattern Notes**:
1. **Provider object**: Not a class, but a plain object with methods attached
2. **specificationVersion**: Must be `'v3' as const`
3. **Throw NoSuchModelError**: For unsupported model types
4. **Default export instance**: `export const pixelart = createPixelArt()`
5. **getHeaders function**: Returns headers, applied per-request in Replicate pattern, or static in OpenAI pattern

