**Example Location**: `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775398555984-v7j1q3/packages/replicate/src/replicate-image-model.ts` (first ~100 lines)

**Minimal structure**:

```typescript
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  FetchFunction,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelartFailedResponseHandler } from './pixelart-error';
import { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const warnings: Array<SharedV3Warning> = [];

    // Parse and validate provider options with schema
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions: options.providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    // Build request
    const requestBody = {
      prompt: options.prompt,
      size: options.size,
      n: options.n,
      // ... additional options
    };

    // Make API call
    const response = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(
        this.config.headers,
        options.headers,
      ),
      body: requestBody,
      failureHandler: pixelartFailedResponseHandler,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map((img: any) => img.b64_json || img.url),
      warnings,
      rawCall: { rawRequest: requestBody, rawResponse: response },
    };
  }
}

const pixelartImageModelOptionsSchema = z.object({
  // Provider-specific options
});
```

