14	export interface ReplicateProviderSettings {
15	  /**
16	   * API token that is being send using the `Authorization` header.
17	   * It defaults to the `REPLICATE_API_TOKEN` environment variable.
18	   */
19	  apiToken?: string;
20	
21	  /**
22	   * Use a different URL prefix for API calls, e.g. to use proxy servers.
23	   * The default prefix is `https://api.replicate.com/v1`.
24	   */
25	  baseURL?: string;
