39	export interface ReplicateProvider extends ProviderV3 {
40	  /**
41	   * Creates a Replicate image generation model.
42	   */
43	  image(modelId: ReplicateImageModelId): ReplicateImageModel;
44	
45	  /**
46	   * Creates a Replicate image generation model.
47	   */
48	  imageModel(modelId: ReplicateImageModelId): ReplicateImageModel;
49	
50	  /**
51	   * @deprecated Use `embeddingModel` instead.
52	   */
53	  textEmbeddingModel(modelId: string): never;
54	
55	  /**
56	   * Creates a Replicate video generation model.
57	   */
58	  video(modelId: ReplicateVideoModelId): Experimental_VideoModelV3;
59	
