66	/**
67	 * Create a Replicate provider instance.
68	 */
69	export function createReplicate(
70	  options: ReplicateProviderSettings = {},
71	): ReplicateProvider {
72	  const getHeaders = () =>
73	    withUserAgentSuffix(
74	      {
75	        Authorization: `Bearer ${loadApiKey({
76	          apiKey: options.apiToken,
77	          environmentVariableName: 'REPLICATE_API_TOKEN',
78	          description: 'Replicate',
79	        })}`,
80	        ...options.headers,
81	      },
82	      `ai-sdk/replicate/${VERSION}`,
83	    );
84	
85	  const createImageModel = (modelId: ReplicateImageModelId) =>
86	    new ReplicateImageModel(modelId, {
87	      provider: 'replicate',
88	      baseURL: options.baseURL ?? 'https://api.replicate.com/v1',
89	      headers: getHeaders(),
90	      fetch: options.fetch,
91	    });
92	
93	  const createVideoModel = (modelId: ReplicateVideoModelId) =>
94	    new ReplicateVideoModel(modelId, {
95	      provider: 'replicate.video',
96	      baseURL: options.baseURL ?? 'https://api.replicate.com/v1',
97	      headers: getHeaders,
98	      fetch: options.fetch,
99	    });
100	
101	  const embeddingModel = (modelId: string) => {
102	    throw new NoSuchModelError({
103	      modelId,
104	      modelType: 'embeddingModel',
105	    });
106	  };
107	
108	  return {
109	    specificationVersion: 'v3' as const,
110	    image: createImageModel,
111	    imageModel: createImageModel,
112	    languageModel: (modelId: string) => {
113	      throw new NoSuchModelError({
114	        modelId,
115	        modelType: 'languageModel',
116	      });
117	    },
118	    embeddingModel,
119	    textEmbeddingModel: embeddingModel,
120	    video: createVideoModel,
121	    videoModel: createVideoModel,
122	  };
123	}
124	
125	/**
126	 * Default Replicate provider instance.
127	 */
128	export const replicate = createReplicate();
